private Class<? extends Void> getVoidClass(@SuppressWarnings("rawtypes") final Class c) throws NoSuchFieldException, SecurityException {

    if (!c.getName().equalsIgnoreCase("void")) {
        Field typeParameterField = ReflectionUtils.getDeclaredField(ReflectUtil.TYPE_PARAMETER_FIELD, c);        
        assertNotNull(typeParameterField);      
        return ((Class<? extends Void>) typeParameterField.get(null));        
    } else {
        return (Class<? extends Void>) c;
    }
}

